package shared

import (
	"encoding/json"
	"github.com/magicbell/magicbell-go/pkg/project-client/internal/clients/rest/httptransport"
	"net/http"
)

// ClientResponse is the user-facing wrapper for API responses.
// It contains the deserialized data, raw HTTP response, and metadata like headers and status code.
type ClientResponse[T any] struct {
	Data     T
	Raw      *http.Response
	Metadata ClientResponseMetadata
}

// ClientResponseMetadata contains HTTP metadata from the API response.
// Includes status code and headers for inspection and debugging.
type ClientResponseMetadata struct {
	Headers    map[string]string
	StatusCode int
}

// NewClientResponse creates a new response wrapper from an internal transport response.
// Extracts data and metadata into a user-facing structure.
func NewClientResponse[T any](resp *httptransport.Response[T]) *ClientResponse[T] {
	return &ClientResponse[T]{
		Data: resp.Data,
		Raw:  resp.Raw,
		Metadata: ClientResponseMetadata{
			StatusCode: resp.StatusCode,
			Headers:    resp.Headers,
		},
	}
}

// GetData returns the deserialized response data.
func (r *ClientResponse[T]) GetData() T {
	return r.Data
}

// String returns a JSON representation of the response for debugging.
// Returns an error message if JSON marshaling fails.
func (r ClientResponse[T]) String() string {
	jsonData, err := json.MarshalIndent(r, "", "  ")
	if err != nil {
		return "error converting struct: ClientResponse to string"
	}
	return string(jsonData)
}

package clientconfig

import (
	"time"

	"github.com/magicbell/magicbell-go/pkg/project-client/internal/clients/rest/hooks"
)

// Config holds all configuration parameters for the SDK client.
// It manages base URL, timeout, authentication credentials, and custom hooks.
type Config struct {
	BaseUrl     *string
	Timeout     *time.Duration
	AccessToken *string
	HookParams  map[string]string
	hook        hooks.Hook
}

// NewConfig creates a new Config instance with default values.
// Sets the base URL to the default environment and timeout to 10 seconds.
func NewConfig() Config {
	baseUrl := DEFAULT_ENVIRONMENT
	timeout := time.Second * 10
	newConfig := Config{
		BaseUrl:    &baseUrl,
		Timeout:    &timeout,
		HookParams: make(map[string]string),
	}

	return newConfig
}

func (c *Config) SetBaseUrl(baseUrl string) {
	c.BaseUrl = &baseUrl
}

func (c *Config) GetBaseUrl() string {
	return *c.BaseUrl
}

func (c *Config) SetTimeout(timeout time.Duration) {
	c.Timeout = &timeout
}

func (c *Config) GetTimeout() time.Duration {
	return *c.Timeout
}

func (c *Config) SetAccessToken(accessToken string) {
	c.AccessToken = &accessToken
}

func (c *Config) GetAccessToken() string {
	return *c.AccessToken
}

package shared

import (
	"github.com/magicbell/magicbell-go/pkg/project-client/internal/clients/rest/httptransport"
	"net/http"
)

// ClientError wraps API errors with detailed metadata including status code, headers, and raw response.
// It implements the error interface and provides structured access to error information.
type ClientError[T any] struct {
	Err      error
	Data     *T
	Body     []byte
	Raw      *http.Response
	Metadata ClientErrorMetadata
}

// ClientErrorMetadata contains HTTP metadata associated with an error response.
type ClientErrorMetadata struct {
	Headers    map[string]string
	StatusCode int
}

// NewClientError creates a new ClientError from an internal transport error.
// It extracts error details, body, status code, and headers into a user-facing error structure.
func NewClientError[T any](transportError *httptransport.ErrorResponse[T]) *ClientError[T] {
	return &ClientError[T]{
		Err:  transportError.GetError(),
		Data: transportError.Data,
		Body: transportError.GetBody(),
		Raw:  transportError.Raw,
		Metadata: ClientErrorMetadata{
			StatusCode: transportError.GetStatusCode(),
			Headers:    transportError.GetHeaders(),
		},
	}
}

// Error implements the error interface, returning the error message string.
func (e *ClientError[T]) Error() string {
	return e.Err.Error()
}

// GetData returns the deserialized error response data.
// Returns nil if unmarshaling failed or the response body was empty.
func (e *ClientError[T]) GetData() *T {
	return e.Data
}

